// Function to retrieve the Usercentrics controllerId from local storage
// and set it as userId in LiveWrapped
async function setUserId() {
  var userId = await window.__ucCmp?.getControllerId();
  if (userId) {
    window.lwhb.cmd.push(function() {
      window.lwhb.userId({
        "userId": userId,
        "userIdModule": true,
        "adServerPpid": true
      });
    });
  }
}

(function() {
  window.lwhb = window.lwhb || {cmd:[]};
  window.highImpactJs = window.highImpactJs || {cmd: []};

  var hash = window.location.hash;
  var storage = window.localStorage;
  if ((hash && hash === "#_ta_") || storage && storage.getItem("_ta_") === "1") {
    window.lwhb.cmd.push(function() {
      window.lwhb.adServerKeywords({
        "ta_ads": "1"
      });
    });
  }

  window.highImpactJs.cmd.push(function() {
    window.highImpactJs.setConfig({
      topBarHeight: 0,
      plugins: ['gam'],
      zIndex: 1,
    });
  });

  // Set userId when CMP is already initialized
  setUserId();

  // Listen for UC initialization event to set userId when user
  // first see the CMP
  window.addEventListener('UC_UI_INITIALIZED', function() {
    setUserId();
  });
})();
